        secretAccessKey: string;
        sessionToken?: string;
        expiration?: Date;
    }>;
};
type TigrisConfig = TigrisEndpointsConfig & TigrisAuthConfig;

/**
 * Unified configuration for Tigris Agentic operations.
 * Accepted directly by both `@tigrisdata/storage` and `@tigrisdata/iam`.
 * When omitted, the underlying SDKs fall back to environment variables.
 */
type TigrisAgentKitConfig = TigrisConfig;

type CheckpointOptions = {
    /** Optional name for the checkpoint snapshot. */
    name?: string;
    config?: TigrisAgentKitConfig;
};
type Checkpoint = {
    snapshotId: string;
    name?: string;
    createdAt?: Date;
};
type RestoreOptions = {
    /** Name for the restored fork bucket. Defaults to `${bucket}-restore-${timestamp}`. */
    forkName?: string;
    config?: TigrisAgentKitConfig;
};
type RestoreResult = {
    bucket: string;
};
type ListCheckpointsOptions = {
    limit?: number;
    paginationToken?: string;
    config?: TigrisAgentKitConfig;
};
type ListCheckpointsResponse = {
    checkpoints: Checkpoint[];
    paginationToken?: string;
};
declare function checkpoint(bucket: string, options?: CheckpointOptions): Promise<TigrisResponse<Checkpoint>>;
declare function restore(bucket: string, snapshotId: string, options?: RestoreOptions): Promise<TigrisResponse<RestoreResult>>;
declare function listCheckpoints(bucket: string, options?: ListCheckpointsOptions): Promise<TigrisResponse<ListCheckpointsResponse>>;

type SetupCoordinationOptions = {
    /** Webhook URL to receive notifications. */
    webhookUrl: string;
    /** Optional key filter regex, e.g. `WHERE \`key\` REGEXP "^results/"`. */
    filter?: string;
    /** Optional authentication for the webhook endpoint. */
    auth?: {
        token: string;
        username?: never;
        password?: never;
    } | {
        username: string;
        password: string;
        token?: never;
    };
    config?: TigrisAgentKitConfig;
};
type TeardownCoordinationOptions = {
    config?: TigrisAgentKitConfig;
};
declare function setupCoordination(bucket: string, options: SetupCoordinationOptions): Promise<TigrisResponse<void>>;
declare function teardownCoordination(bucket: string, options?: TeardownCoordinationOptions): Promise<TigrisResponse<void>>;

type CreateForksOptions = {
    /** Prefix for fork bucket names. Defaults to `${baseBucket}-fork-${timestamp}`. */
    prefix?: string;
    /** If provided, creates a scoped access key per fork with this role. */
    credentials?: {
        role: 'Editor' | 'ReadOnly';
    };
    config?: TigrisAgentKitConfig;
};
type Fork = {
    bucket: string;
    credentials?: {
        accessKeyId: string;
        secretAccessKey: string;
    };
};
type Forks = {
    baseBucket: string;
    snapshotId: string;
    forks: Fork[];
};
type TeardownForksOptions = {
    config?: TigrisAgentKitConfig;
};
declare function createForks(baseBucket: string, count: number, options?: CreateForksOptions): Promise<TigrisResponse<Forks>>;
declare function teardownForks(forkSet: Forks, options?: TeardownForksOptions): Promise<TigrisResponse<void>>;

type CreateWorkspaceOptions = {
    access?: 'public' | 'private';
    /** Auto-expire objects after this many days. */
    ttl?: {
        days: number;
    };
    enableSnapshots?: boolean;
    /** If provided, creates a scoped access key with this role. */
    credentials?: {
        role: 'Editor' | 'ReadOnly';
    };
    config?: TigrisAgentKitConfig;
};
type Workspace = {
    bucket: string;
    credentials?: {
        accessKeyId: string;
        secretAccessKey: string;
    };
};
type TeardownWorkspaceOptions = {
    config?: TigrisAgentKitConfig;
};
declare function createWorkspace(name: string, options?: CreateWorkspaceOptions): Promise<TigrisResponse<Workspace>>;
declare function teardownWorkspace(workspace: Workspace, options?: TeardownWorkspaceOptions): Promise<TigrisResponse<void>>;

export { type Checkpoint, type CheckpointOptions, type CreateForksOptions, type CreateWorkspaceOptions, type Fork, type Forks, type ListCheckpointsOptions, type ListCheckpointsResponse, type RestoreOptions, type RestoreResult, type SetupCoordinationOptions, type TeardownCoordinationOptions, type TeardownForksOptions, type TeardownWorkspaceOptions, type TigrisAgentKitConfig, type Workspace, checkpoint, createForks, createWorkspace, listCheckpoints, restore, setupCoordination, teardownCoordination, teardownForks, teardownWorkspace };

type TigrisStorageConfig = {
    bucket?: string;
    accessKeyId?: string;
    secretAccessKey?: string;
    endpoint?: string;
};
type TigrisStorageResponse<T, E = Error> = {
    data: T;
    error?: never;
} | {
    error: E;
    data?: never;
};

type CreateBucketOptions = {
    enableSnapshot?: boolean;
    sourceBucketName?: string;
    sourceBucketSnapshot?: string;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function createBucket(bucketName: string, options?: CreateBucketOptions): Promise<TigrisStorageResponse<void, Error>>;

type ListBucketSnapshotsOptions = {
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
type ListBucketSnapshotsResponse = Array<{
    snapshotName: string | undefined;
    creationDate: Date | undefined;
}>;
declare function listBucketSnapshots(options?: ListBucketSnapshotsOptions): Promise<TigrisStorageResponse<ListBucketSnapshotsResponse, Error>>;
declare function listBucketSnapshots(sourceBucketName?: string, options?: ListBucketSnapshotsOptions): Promise<TigrisStorageResponse<ListBucketSnapshotsResponse, Error>>;
type CreateBucketSnapshotOptions = {
    name?: string;
    /**
     * @deprecated Use name instead, will be removed in the next major version
     */
    description?: string;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function createBucketSnapshot(options?: CreateBucketSnapshotOptions): Promise<TigrisStorageResponse<void, Error>>;
declare function createBucketSnapshot(sourceBucketName?: string, options?: CreateBucketSnapshotOptions): Promise<TigrisStorageResponse<void, Error>>;

type GetOptions = {
    config?: TigrisStorageConfig;
    contentDisposition?: 'attachment' | 'inline';
    contentType?: string;
    encoding?: string;
};
type GetResponse = string | File | ReadableStream;
declare function get(path: string, format: 'string', options?: GetOptions): Promise<TigrisStorageResponse<string, Error>>;
declare function get(path: string, format: 'file', options?: GetOptions): Promise<TigrisStorageResponse<File, Error>>;
declare function get(path: string, format: 'stream', options?: GetOptions): Promise<TigrisStorageResponse<ReadableStream, Error>>;

type HeadOptions = {
    config?: TigrisStorageConfig;
};
type HeadResponse = {
    contentDisposition: string;
    contentType: string;
    modified: Date;
    path: string;
    size: number;
    url: string;
};
declare function head(path: string, options?: HeadOptions): Promise<TigrisStorageResponse<HeadResponse, Error> | undefined>;

type ListOptions = {
    limit?: number;
    paginationToken?: string;
    config?: TigrisStorageConfig;
};
type ListItem = {
    id: string;
    name: string;
    size: number;
    lastModified: Date;
};
type ListResponse = {
    items: ListItem[];
    paginationToken: string | undefined;
    hasMore: boolean;
};
declare function list(options?: ListOptions): Promise<TigrisStorageResponse<ListResponse, Error>>;

type InitMultipartUploadOptions = {
    config?: TigrisStorageConfig;
};
type InitMultipartUploadResponse = {
    uploadId: string;
};
declare function initMultipartUpload(path: string, options?: InitMultipartUploadOptions): Promise<TigrisStorageResponse<InitMultipartUploadResponse, Error>>;
type GetPartsPresignedUrlsOptions = {
    config?: TigrisStorageConfig;
};
type GetPartsPresignedUrlsResponse = Array<{
    part: number;
    url: string;
}>;
declare function getPartsPresignedUrls(path: string, parts: number[], uploadId: string, options?: GetPartsPresignedUrlsOptions): Promise<TigrisStorageResponse<GetPartsPresignedUrlsResponse, Error>>;
type CompleteMultipartUploadOptions = {
    config?: TigrisStorageConfig;
};
type CompleteMultipartUploadResponse = {
    path: string;
    url: string;
};
declare function completeMultipartUpload(path: string, uploadId: string, partIds: Array<{
    [key: number]: string;
}>, options?: CompleteMultipartUploadOptions): Promise<TigrisStorageResponse<CompleteMultipartUploadResponse, Error>>;

type GetPresignedUrlOperation = 'get' | 'put';
type MethodOrOperation = {
    method: GetPresignedUrlOperation;
    operation?: never;
} | {
    operation: GetPresignedUrlOperation;
    method?: never;
};
type GetPresignedUrlOptions = {
    expiresIn?: number;
    contentType?: string;
    config?: TigrisStorageConfig;
} & MethodOrOperation;
type GetPresignedUrlResponse = {
    url: string;
    expiresIn: number;
} & MethodOrOperation;
declare function getPresignedUrl(path: string, options: GetPresignedUrlOptions): Promise<TigrisStorageResponse<GetPresignedUrlResponse, Error>>;

type PutOnUploadProgress = ({ loaded, total, percentage, }: {
    loaded: number;
    total: number;
    percentage: number;
}) => void;
type PutOptions = {
    access?: 'public' | 'private';
    addRandomSuffix?: boolean;
    allowOverwrite?: boolean;
    contentType?: string;
    contentDisposition?: 'attachment' | 'inline';
    multipart?: boolean;
    abortController?: AbortController;
    onUploadProgress?: PutOnUploadProgress;
    config?: TigrisStorageConfig;
};
type PutResponse = {
    contentDisposition: string | undefined;
    contentType: string | undefined;
    modified: Date;
    path: string;
    size: number;
    url: string;
};
declare function put(path: string, body: string | ReadableStream | Blob | Buffer, options?: PutOptions): Promise<TigrisStorageResponse<PutResponse, Error>>;

type RemoveOptions = {
    config?: TigrisStorageConfig;
