import fs from "node:fs/promises";
import path from "node:path";
import {
  S3Client,
  PutObjectCommand,
  DeleteBucketCommand,
  DeleteObjectCommand,
  ListObjectsV2Command,
} from "@aws-sdk/client-s3";
import { checkpoint, restore } from "@tigrisdata/agent-kit";

// ── 0. Derive bucket name ────────────────────────────────────────────────────
const trialIdRaw = (
  await fs.readFile("/logs/artifacts/trial_id", "utf-8")
).trim();

// S3 bucket names: lowercase letters, numbers, dots, hyphens only
const trialId = trialIdRaw.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
const bucketName = `harbor-awscli-${trialId}`;

console.log(`Trial ID  : ${trialIdRaw}`);
console.log(`Bucket    : ${bucketName}`);

// ── AWS S3 client pointed at Tigris ─────────────────────────────────────────
const s3 = new S3Client({
  region: "REDACTED",
  endpoint: "REDACTED",
  credentials: {
    accessKeyId: process.env.TIGRIS_STORAGE_ACCESS_KEY_ID!,
    secretAccessKey: process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY!,
  },
});

// ── 1. Upload v1 ─────────────────────────────────────────────────────────────
console.log("\n[1] Uploading v1.txt (version=1) …");
await s3.send(
  new PutObjectCommand({
    Bucket: bucketName,
    Key: "v1.txt",
    Body: Buffer.from("version=1", "utf-8"),
    ContentType: "text/plain",
  })
);
console.log("    ✓ v1.txt uploaded");

// ── 2. Checkpoint ─────────────────────────────────────────────────────────────
console.log("\n[2] Creating checkpoint 'before-mutation' …");
const { data: ckpt, error: ckptErr } = await checkpoint(bucketName, {
  name: "before-mutation",
});
if (ckptErr) {
  throw new Error(`Checkpoint failed: ${ckptErr.message}`);
}
console.log(`    ✓ snapshotId = ${ckpt.snapshotId}`);

// ── 3. Mutate ─────────────────────────────────────────────────────────────────
console.log("\n[3] Overwriting v1.txt with version=2 …");
await s3.send(
  new PutObjectCommand({
    Bucket: bucketName,
    Key: "v1.txt",
    Body: Buffer.from("version=2", "utf-8"),
    ContentType: "text/plain",
  })
);
console.log("    ✓ v1.txt mutated to version=2");

// ── 4. Restore ────────────────────────────────────────────────────────────────
console.log("\n[4] Restoring checkpoint into fork 'rollback-recovery' …");
const { data: restored, error: restoreErr } = await restore(
  bucketName,
  ckpt.snapshotId,
  { forkName: "rollback-recovery" }
);
if (restoreErr) {
  throw new Error(`Restore failed: ${restoreErr.message}`);
}
const recoveryBucket = restored.bucket;
console.log(`    ✓ recovery bucket = ${recoveryBucket}`);

// Write recovery.json
const recoveryJsonPath = path.join(
  path.dirname(new URL(import.meta.url).pathname),
  "recovery.json"
);
await fs.writeFile(
  recoveryJsonPath,
  JSON.stringify({ recoveryBucket }, null, 2),
  "utf-8"
);
console.log(`    ✓ Written recovery.json`);

// ── 5. Tear down the recovery fork ──────────────────────────────────────────
console.log("\n[5] Deleting recovery fork bucket …");

// Empty the fork bucket first (S3 requires bucket to be empty before deletion)
let continuationToken: string | undefined;
do {
  const listResp = await s3.send(
    new ListObjectsV2Command({
      Bucket: recoveryBucket,
      ContinuationToken: continuationToken,
    })
  );
  const objects = listResp.Contents ?? [];
  for (const obj of objects) {
    if (obj.Key) {
      await s3.send(
        new DeleteObjectCommand({ Bucket: recoveryBucket, Key: obj.Key })
      );
    }
  }
  continuationToken = listResp.IsTruncated
    ? listResp.NextContinuationToken
    : undefined;
} while (continuationToken);

await s3.send(new DeleteBucketCommand({ Bucket: recoveryBucket }));
console.log(`    ✓ Recovery fork bucket '${recoveryBucket}' deleted`);

console.log("\n✅ All steps completed successfully.");

