type TigrisResponse<T, E = Error> = {
    data: T;
    error?: never;
} | {
    error: E;
    data?: never;
};
type TigrisEndpointsConfig = {
    endpoint?: string;
    iamEndpoint?: string;
    mgmtEndpoint?: string;
};
type TigrisAuthConfig = {
    accessKeyId?: string;
    secretAccessKey?: string;
    sessionToken?: string;
    organizationId?: string;
    credentialProvider?: () => Promise<{
        accessKeyId: string;
        secretAccessKey: string;
        sessionToken?: string;
        expiration?: Date;
    }>;
};
type TigrisConfig = TigrisEndpointsConfig & TigrisAuthConfig;

type TigrisStorageConfig = {
    bucket?: string;
    forcePathStyle?: boolean;
} & TigrisConfig;
type TigrisStorageResponse<T, E = Error> = TigrisResponse<T, E>;

declare const multiRegions: readonly ["usa", "eur"];
declare const singleOrDualRegions: readonly ["ams", "fra", "gru", "iad", "jnb", "lhr", "nrt", "ord", "sin", "sjc", "syd"];
type StorageClass = 'STANDARD' | 'STANDARD_IA' | 'GLACIER' | 'GLACIER_IR';
type BucketLocationMulti = (typeof multiRegions)[number];
type BucketLocationDualOrSingle = (typeof singleOrDualRegions)[number];
type BucketLocations = {
    type: 'multi';
    values: BucketLocationMulti;
} | {
    type: 'dual';
    values: BucketLocationDualOrSingle | BucketLocationDualOrSingle[];
} | {
    type: 'single';
    values: BucketLocationDualOrSingle;
} | {
    type: 'global';
    values?: never;
};
type BucketMigration = {
    enabled: boolean;
    accessKey?: string;
    secretKey?: string;
    region?: string;
    name?: string;
    endpoint?: string;
    writeThrough?: boolean;
};
/**
 * Bucket-wide TTL configuration. Kept for back-compat with `setBucketTtl`,
 * which manages a lifecycle rule with only `expiration` (no transition,
 * no filter). New code should configure expirations via
 * `BucketLifecycleRule.expiration` on `setBucketLifecycle` instead. This
 * shape is expected to be removed in the next major version.
 */
type BucketTtl = {
    id?: string;
    enabled?: boolean;
    days?: number;
    date?: string;
};
type BucketLifecycleFilter = {
    prefix: string;
};
type BucketLifecycleExpiration = {
    days?: number;
    date?: string;
};
/**
 * A bucket lifecycle rule. A rule can have at most one transition
 * (top-level `storageClass` + `days`/`date`) and/or one `expiration`,
 * optionally scoped to a key prefix via `filter.prefix`. At least one
 * of transition or expiration must be present.
 */
type BucketLifecycleRule = {
    id?: string;
    enabled?: boolean;
    storageClass?: Exclude<StorageClass, 'STANDARD'>;
    days?: number;
    date?: string;
    expiration?: BucketLifecycleExpiration;
    filter?: BucketLifecycleFilter;
};
type BucketCorsRule = {
    allowedOrigins: string | string[];
    allowedMethods?: string | string[];
    allowedHeaders?: string | string[];
    exposeHeaders?: string | string[];
    maxAge?: number;
};
type BucketNotificationBase = {
    enabled?: boolean;
    url?: string;
    filter?: string;
};
type BucketNotificationBasicAuth = BucketNotificationBase & {
    auth: {
        username: string;
        password: string;
        token?: never;
    };
};
type BucketNotificationTokenAuth = BucketNotificationBase & {
    auth: {
        token: string;
        username?: never;
        password?: never;
    };
};
type BucketNotification = BucketNotificationBase | BucketNotificationBasicAuth | BucketNotificationTokenAuth;
/**
 * Recognized event types Tigris fires for object notifications.
 *
 * The union is open — when Tigris adds new event types, consumers
 * keep REDACTEDcomplete on the known values without crashing on unknowns.
 * See https://www.tigrisdata.com/docs/buckets/object-notifications/
 */
type NotificationEventName = 'OBJECT_CREATED_PUT' | 'OBJECT_DELETED' | (string & {});
/**
 * A single event in a bucket-notification webhook delivery. Mirrors the
 * wire format Tigris POSTs to the configured webhook URL — no
 * normalization, no flattening. Cast `await req.json()` to
 * `NotificationResponse` (or run a runtime validator like Zod) at the
 * receiving end and switch on `eventName`.
 *
 * See https://www.tigrisdata.com/docs/buckets/object-notifications/
 */
type NotificationEvent = {
    /** Schema version of the event payload. */
    eventVersion: string;
    /** Source identifier (`"tigris"` today). */
    eventSource: string;
    /** Event type. Open union: see {@link NotificationEventName}. */
    eventName: NotificationEventName;
    /** RFC 3339 timestamp the event occurred at. */
    eventTime: string;
    /** Bucket the object belongs to. */
    bucket: string;
    /** Object metadata. */
    object: {
        /** Object key inside the bucket. */
        key: string;
        /** Object size in bytes. */
        size: number;
        /** Object ETag (typically MD5 hex). */
        eTag: string;
    };
};
/**
 * Top-level shape of a bucket-notification webhook POST body. A single
 * delivery may carry multiple events — iterate `response.events`.
 *
 * See https://www.tigrisdata.com/docs/buckets/object-notifications/
 */
type NotificationResponse = {
    events: NotificationEvent[];
};
type UpdateBucketResponse = {
    bucket: string;
    updated: boolean;
};

type CreateBucketOptions = {
    enableSnapshot?: boolean;
    sourceBucketName?: string;
    sourceBucketSnapshot?: string;
    access?: 'public' | 'private';
    defaultTier?: StorageClass;
    locations?: BucketLocations;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
type CreateBucketResponse = {
    isSnapshotEnabled: boolean;
    hasForks: boolean;
    sourceBucketName?: string;
    sourceBucketSnapshot?: string;
};
declare function createBucket(bucketName: string, options?: CreateBucketOptions): Promise<TigrisStorageResponse<CreateBucketResponse, Error>>;

type GetBucketInfoOptions = {
    config?: TigrisStorageConfig;
};
type BucketInfoResponse = {
    isSnapshotEnabled: boolean;
    forkInfo: {
        hasChildren: boolean;
        parents: Array<{
            bucketName: string;
            forkCreatedAt: Date;
            snapshot: string;
            snapshotCreatedAt: Date;
        }>;
    } | undefined;
    settings: {
        allowObjectAcl: boolean;
        defaultTier: StorageClass;
        lifecycleRules?: BucketLifecycleRule[];
        dataMigration?: Omit<BucketMigration, 'enabled'>;
        /**
         * @deprecated Use `lifecycleRules` instead. This field is no longer
         * populated — read the rule with only `expiration` (no transition,
         * no filter) from `lifecycleRules` if you need the bucket-wide TTL.
         */
        ttlConfig?: BucketTtl;
        customDomain?: string;
        deleteProtection: boolean;
        corsRules: BucketCorsRule[];
        additionalHeaders?: Record<string, string>;
        notifications?: BucketNotification;
    };
    sizeInfo: {
        numberOfObjects: number | undefined;
        size: number | undefined;
        numberOfObjectsAllVersions: number | undefined;
    };
};
declare function getBucketInfo(bucketName: string, options?: GetBucketInfoOptions): Promise<TigrisStorageResponse<BucketInfoResponse, Error>>;

type ListBucketsOptions = {
    config?: TigrisStorageConfig;
    paginationToken?: string;
    limit?: number;
};
type ListBucketsResponse = {
    buckets: Bucket[];
    owner?: BucketOwner;
    paginationToken?: string;
};
type Bucket = {
    name: string;
    creationDate: Date;
};
type BucketOwner = {
    name: string;
    id: string;
};
declare function listBuckets(options?: ListBucketsOptions): Promise<TigrisStorageResponse<ListBucketsResponse, Error>>;

type RemoveBucketOptions = {
    force?: boolean;
    config?: TigrisStorageConfig;
};
declare function removeBucket(bucketName: string, options?: RemoveBucketOptions): Promise<TigrisStorageResponse<void, Error>>;

type SetBucketCorsOptions = {
    config?: Omit<TigrisStorageConfig, 'bucket'>;
    override?: boolean;
    rules: BucketCorsRule[];
};
declare function setBucketCors(bucketName: string, options?: SetBucketCorsOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type SetBucketLifecycleOptions = {
    lifecycleRules: BucketLifecycleRule[];
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function setBucketLifecycle(bucketName: string, options?: SetBucketLifecycleOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type SetBucketMigrationOptions = {
    dataMigration?: BucketMigration;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function setBucketMigration(bucketName: string, options?: SetBucketMigrationOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type SetBucketNotificationsOptions = {
    config?: Omit<TigrisStorageConfig, 'bucket'>;
    notificationConfig: BucketNotification;
    override?: boolean;
};
/**
 * Configure webhook notifications for object events on a bucket.
 *
 * **Scenarios:**
 *
 * 1. If `notificationConfig` is empty (`{}`), sends it as-is to clear notifications.
 *
 * 2. If only `enabled` is provided, fetches the existing config and merges
 *    with the new `enabled` value. Errors if no existing config is found.
 *
 * 3. If config is provided without `enabled`, fetches existing config and
 *    merges, retaining the existing `enabled` value.
 *
 * 4. `url` is validated when provided (must be a valid http/https URL).
 *
 * 5. `auth.username` and `auth.password` are validated when provided.
 *
 * 6. `auth.token` is validated when provided.
 *
 * 7. `auth.token` and `auth.username`/`auth.password` cannot be provided together.
 *
 * 8. `override` replaces the existing config when `true`.
 *    When `false` (default), merges with the existing config.
 */
declare function setBucketNotifications(bucketName: string, options: SetBucketNotificationsOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type SetBucketTtlOptions = {
    ttlConfig?: BucketTtl;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function setBucketTtl(bucketName: string, options?: SetBucketTtlOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type ListBucketSnapshotsOptions = {
    config?: Omit<TigrisStorageConfig, 'bucket'>;
    paginationToken?: string;
    limit?: number;
};
type BucketSnapshot = {
    name?: string | undefined;
    version: string | undefined;
    creationDate: Date | undefined;
};
type ListBucketSnapshotsResponse = {
    snapshots: BucketSnapshot[];
    paginationToken?: string;
};
declare function listBucketSnapshots(options?: ListBucketSnapshotsOptions): Promise<TigrisStorageResponse<ListBucketSnapshotsResponse, Error>>;
declare function listBucketSnapshots(sourceBucketName?: string, options?: ListBucketSnapshotsOptions): Promise<TigrisStorageResponse<ListBucketSnapshotsResponse, Error>>;
type CreateBucketSnapshotOptions = {
    name?: string;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
type CreateBucketSnapshotResponse = {
    snapshotVersion: string;
};
declare function createBucketSnapshot(options?: CreateBucketSnapshotOptions): Promise<TigrisStorageResponse<CreateBucketSnapshotResponse, Error>>;
declare function createBucketSnapshot(sourceBucketName?: string, options?: CreateBucketSnapshotOptions): Promise<TigrisStorageResponse<CreateBucketSnapshotResponse, Error>>;

type UpdateBucketOptions = {
    access?: 'public' | 'private';
    allowObjectAcl?: boolean;
    disableDirectoryListing?: boolean;
    locations?: BucketLocations;
    cacheControl?: string;
    customDomain?: string;
    enableAdditionalHeaders?: boolean;
    enableDeleteProtection?: boolean;
    config?: Omit<TigrisStorageConfig, 'bucket'>;
};
declare function updateBucket(bucketName: string, options?: UpdateBucketOptions): Promise<TigrisStorageResponse<UpdateBucketResponse, Error>>;

type BundleOptions = {
    config?: TigrisStorageConfig;
    /**
     * Compression algorithm for the response.
     * - `"none"` (default): No compression. Best for already-compressed data (JPEG, PNG).
     * - `"gzip"`: Gzip compression.
     * - `"zstd"`: Zstd compression. Best ratio + speed for large bundles.
     */
    compression?: 'none' | 'gzip' | 'zstd';
    /**
     * Error handling mode for missing objects.
     * - `"skip"` (default): Omit missing objects and append `__bundle_errors.json` to the tar.
     * - `"fail"`: Return an error before streaming if any object is missing.
     */
    onError?: 'skip' | 'fail';
};
type BundleResponse = {
    /** The streaming tar archive body. Caller is responsible for consuming and closing. */
    body: ReadableStream;
    /** The response Content-Type (e.g. "application/x-tar", "application/gzip"). */
    contentType: string;
};
/**
 * Fetch multiple objects from a bucket as a streaming tar archive in a single request.
 *
 * This is a Tigris extension to the S3 API, designed for ML training workloads
 * that need to fetch thousands of objects per batch without per-object HTTP overhead.
 *
 * @example
 * ```ts
 * const result = await bundle(["img_001.jpg", "img_002.jpg"], {
 *   config: { bucket: "my-bucket" },
 * });
 * if (result.error) throw result.error;
 *
 * const reader = result.data.body.getReader();
 * ```
 *
 * @param keys - Array of object keys to include in the bundle (max 5,000).
 * @param options - Optional configuration including bucket, compression, and error handling.
 */
declare function bundle(keys: string[], options?: BundleOptions): Promise<TigrisStorageResponse<BundleResponse, Error>>;

type CopyOptions = {
    config?: TigrisStorageConfig;
    /** Source bucket. Defaults to `config.bucket`. */
    srcBucket?: string;
    /** Destination bucket. Defaults to `srcBucket` (same-bucket copy). */
    destBucket?: string;
};
type CopyResponse = {
    src: string;
    dest: string;
};
declare function copy(src: string, dest: string, options?: CopyOptions): Promise<TigrisStorageResponse<CopyResponse, Error>>;

type GetOptions = {
    config?: TigrisStorageConfig;
    contentDisposition?: 'attachment' | 'inline';
    contentType?: string;
    encoding?: string;
    snapshotVersion?: string;
    versionId?: string;
};
type GetResponse = string | File | ReadableStream;
declare function get(path: string, format: 'string', options?: GetOptions): Promise<TigrisStorageResponse<string, Error>>;
declare function get(path: string, format: 'file', options?: GetOptions): Promise<TigrisStorageResponse<File, Error>>;
declare function get(path: string, format: 'stream', options?: GetOptions): Promise<TigrisStorageResponse<ReadableStream, Error>>;

type HeadOptions = {
    snapshotVersion?: string;
