import fs from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";
import {
  S3Client,
  PutObjectCommand,
  DeleteBucketCommand,
  CreateBucketCommand,
  DeleteObjectCommand,
  ListObjectsV2Command,
} from "@aws-sdk/client-s3";
import { checkpoint, restore } from "@tigrisdata/agent-kit";

// ── 0. Derive bucket name ────────────────────────────────────────────────────
const trialIdRaw = (
  await fs.readFile("/logs/artifacts/trial_id", "utf-8")
).trim();

// S3 bucket names: lowercase letters, numbers, dots, hyphens only
const trialId = trialIdRaw.toLowerCase().replace(/[^a-z0-9.-]/g, "-");
const bucketName = `harbor-awscli-${trialId}`;

console.log(`Trial ID  : ${trialIdRaw}`);
console.log(`Bucket    : ${bucketName}`);

// ── AWS S3 client pointed at Tigris ─────────────────────────────────────────
const endpoint = "REDACTED";
const credentials = {
  accessKeyId: process.env.TIGRIS_STORAGE_ACCESS_KEY_ID!,
  secretAccessKey: process.env.TIGRIS_STORAGE_SECRET_ACCESS_KEY!,
};

const s3 = new S3Client({
  region: "REDACTED",
  endpoint,
  credentials,
});

// ── Helper: sleep ─────────────────────────────────────────────────────────────
const sleep = (ms: number) =>
  new Promise<void>((resolve) => setTimeout(resolve, ms));

// ── Ensure snapshots are enabled on the bucket ───────────────────────────────
// The bucket is pre-created; we (re-)create it with X-Tigris-Enable-Snapshot
// which is idempotent: if bucket exists without snapshots, Tigris enables them;
// if already enabled it returns 409/200 either way.
console.log("\n[0] Ensuring snapshot feature is enabled on bucket …");
const enableSnapshotCmd = new CreateBucketCommand({ Bucket: bucketName });
enableSnapshotCmd.middlewareStack.add(
  (next) => async (args) => {
    (args.request as any).headers["X-Tigris-Enable-Snapshot"] = "true";
    return next(args);
  },
  { step: "build" }
);
try {
  await s3.send(enableSnapshotCmd);
  console.log("    ✓ Bucket (re-)created with snapshot feature enabled");
} catch (err: any) {
  const code = err.Code ?? err.name ?? "";
  const status = err.$metadata?.httpStatusCode ?? 0;
  if (
    code === "BucketAlreadyOwnedByYou" ||
    code === "BucketAlreadyExists" ||
    status === 409
  ) {
    console.log("    ✓ Bucket already exists (snapshot feature enabled)");
  } else {
    throw err;
  }
}

// ── 1. Upload v1 ─────────────────────────────────────────────────────────────
console.log("\n[1] Uploading v1.txt (version=1) …");
await s3.send(
  new PutObjectCommand({
    Bucket: bucketName,
    Key: "v1.txt",
    Body: Buffer.from("version=1", "utf-8"),
    ContentType: "text/plain",
  })
);
console.log("    ✓ v1.txt uploaded");

// ── 2. Checkpoint ─────────────────────────────────────────────────────────────
console.log("\n[2] Creating checkpoint 'before-mutation' …");
const { data: ckpt, error: ckptErr } = await checkpoint(bucketName, {
  name: "before-mutation",
});
if (ckptErr) {
  throw new Error(`Checkpoint failed: ${ckptErr.message}`);
}
console.log(`    ✓ snapshotId = ${ckpt.snapshotId}`);

// ── 3. Mutate ─────────────────────────────────────────────────────────────────
console.log("\n[3] Overwriting v1.txt with version=2 …");
await s3.send(
  new PutObjectCommand({
    Bucket: bucketName,
    Key: "v1.txt",
    Body: Buffer.from("version=2", "utf-8"),
    ContentType: "text/plain",
  })
);
console.log("    ✓ v1.txt mutated to version=2");

// ── 4. Restore ────────────────────────────────────────────────────────────────
console.log("\n[4] Restoring checkpoint into fork 'rollback-recovery' …");

// Retry loop: bucket deletion propagation can cause transient failures
let restored: { bucket: string } | undefined;
const MAX_RESTORE_RETRIES = 10;
const RESTORE_RETRY_DELAY_MS = 8000;
for (let attempt = 1; attempt <= MAX_RESTORE_RETRIES; attempt++) {
  const { data, error: restoreErr } = await restore(
    bucketName,
    ckpt.snapshotId,
    { forkName: "rollback-recovery" }
  );
  if (restoreErr) {
    if (attempt < MAX_RESTORE_RETRIES) {
      console.log(
        `    ⚠ Restore attempt ${attempt} failed (${restoreErr.message}), retrying in ${RESTORE_RETRY_DELAY_MS / 1000}s …`
      );
      await sleep(RESTORE_RETRY_DELAY_MS);
    } else {
      throw new Error(`Restore failed after ${MAX_RESTORE_RETRIES} attempts: ${restoreErr.message}`);
    }
  } else {
    restored = data;
    break;
  }
}

const recoveryBucket = restored!.bucket;
console.log(`    ✓ recovery bucket = ${recoveryBucket}`);

// Write recovery.json
const __dirname = path.dirname(fileURLToPath(import.meta.url));
const recoveryJsonPath = path.join(__dirname, "recovery.json");
await fs.writeFile(
  recoveryJsonPath,
  JSON.stringify({ recoveryBucket }, null, 2),
  "utf-8"
);
console.log(`    ✓ Written recovery.json`);

// ── 5. Tear down the recovery fork ──────────────────────────────────────────
console.log("\n[5] Deleting recovery fork bucket …");

// Empty the fork bucket first (S3 requires bucket to be empty before deletion)
let continuationToken: string | undefined;
do {
  const listResp = await s3.send(
    new ListObjectsV2Command({
      Bucket: recoveryBucket,
      ContinuationToken: continuationToken,
    })
  );
  const objects = listResp.Contents ?? [];
  for (const obj of objects) {
    if (obj.Key) {
      await s3.send(
        new DeleteObjectCommand({ Bucket: recoveryBucket, Key: obj.Key })
      );
    }
  }
  continuationToken = listResp.IsTruncated
    ? listResp.NextContinuationToken
    : undefined;
} while (continuationToken);

await s3.send(new DeleteBucketCommand({ Bucket: recoveryBucket }));
console.log(`    ✓ Recovery fork bucket '${recoveryBucket}' deleted`);

console.log("\n✅ All steps completed successfully.");
